INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00264', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「情感像微雲流過柔藍的天空，要追摹它的跡象，就如在月光下搜尋瀑布映在石壁上的影子，用文字 把那影子描下來，保留的已極有限，於是詩一部分歪曲，一部分湮滅，一部分不自覺地擴大，真正詩 人的情緒讀者所能共感的，不就像幾縷夢的游絲了嗎？因此詩特別講暗示，重言外的神韻，不專求表 現，而在使讀者就有限的文字填滿無窮的虛白。」 根據上文，下列選項何者最符合作者對詩歌的看法？', '["講究氣若游絲的情感", "獲得天馬行空的愉悅", "重視含蓄幽微的情韻", "追求恍惚縹緲的風格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00265', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '孔子說：「父母在世的時候，子女應當體察父母的心意；父母過世以後，就應當體察父母的遺行。能 夠長久不改變父母的善行，就可以說是盡孝了。」 根據上文，下列選項何者最符合孝子的條件？', '["百順百依", "克紹箕裘", "傳宗接代", "樂善好施"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00266', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「孔子說：『溫故而知新』，一般常解釋為溫習曾學習過的知識，並汲取未曾學習的新知。但考慮孔子 對於傳統文化常有自己的想法，『溫故而知新』也可以解釋為在對舊有文化的了解中， ， 從而形成新的文化傳統。這也是孔子之所以認同周代除了對商代之禮有所繼承外，也有所改動的原 因。」 根據文意，畫底線處最適合填入的選項是：', '["加以修正調整，從中挖掘出新意", "儘量繼承原貌，著墨細節不馬虎", "新形式包裝舊理論，大同而小異", "努力改造傳統，移植進步新文明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00267', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「書法不只是藝術，也是傳遞思想的文字；繪畫不只是筆墨，也是傳達人生理想的詩篇；哲學和藝術 不只是存在士大夫腦間的雲霧，也落於市井小民，成為順口拋出的淺俗俚語；達摩不只是宗教的尖端， 也落實在街頭賣膏藥老頭的禿筆之下。有如此的『俗』，才有無上的『雅』。雅可以不避湫穢的擁抱俗， 而俗可以溫暖、烘承大雅，成為人類文化的巔峰。」 根據上文，下列選項何者最符合作者心目中的藝術？', '["故宮博物院典藏之作，才是真正的藝術品", "雅俗共賞的達摩像，蘊藏文化傳燈的幽光", "市井小民與士大夫之間的審美觀相差無幾", "民俗藝術最終會成為茶餘飯後重要的題材"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00268', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「春已在這些樹林中間，在淒黃的老葉間，又一度偷偷地刷上了油然的新綠，使得這些長在得天獨厚 的南天之下的樹木，蓬勃而倔強又多上了旺盛的生命之火，彷彿懵然不知自然界循環交替的法則一 般。」 根據上文，下列選項何者正確？', '["感嘆即使一度新綠，老葉終將隨自然循環淒黃", "羨慕南方樹木得天獨厚完全沒有季節變化痕跡", "欣喜春回大地，原已強健的樹林更顯生機勃發", "惋惜樹林以生命之火挺過冬天卻不知面臨交替"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00269', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「日本庭園根據風格形式，大致可分成池泉式、淨土式、枯山水、露池、大名庭園與借景式庭園等幾 種類型。每種形式都有它的特定的背景與思維，例如，來自中國的神仙思想，融合日本原始的自然信 仰，發展出池泉式庭園，水池中央的疊山，象徵著蓬萊、方丈、瀛洲等三座仙山，無論是舟遊或是回 遊，都隱含著尋道修真的長生追求。」 根據上文，下列選項何者最符合日本池泉式庭園風格的設計理念？', '["體現神仙思想與宗教信仰", "取用自然泉水以灌溉花木", "符合僧道遊仙禪修的生活需求", "順應中日兩國交流的文化風潮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00270', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「英國人類學家羅賓．鄧巴發現，人類能夠維持的穩定社交人數在150人上下，超出這個數字就會引 發認知焦慮，也就是所謂的『鄧巴數』。現代人朋友圈的好友人數或許已遠超過這個上限，但這些朋 友，或者說這些『聯繫』，是真正的『聯繫』嗎？那些隨手按的讚、那些隻字片語的回覆，真的可以替 代一次深夜裡的促膝長談嗎？在社交媒體的轟炸下，人愈來愈難以獨處。孤獨成了亟待解決的問題。 即使是幾秒鐘的孤獨，也會被無限放大，轉而求助更多的『聯繫』，卻反而加深焦慮，形成惡性循環。」 根據上文，下列選項何者最正確？', '["鄧巴數告訴我們，朋友的數量與真實的快樂呈現絕對的反比關係", "朋友在精不在多，與其追求數量的累積，不如交幾個真心的朋友", "如果能在社交媒體上獲得眾人的關心與安慰，孤獨感就一定不會出現", "社交平台上與朋友聯繫信息數量的多寡與人們內心焦慮的感受成正比"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00271', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「人生像一盒火柴，慎重處理太愚蠢，不慎重處理是危險的。」下列選項，何者最符合文意？', '["燃燒自己，照亮別人", "高低起伏，伺機而動", "隨順緣分，俯仰自然", "張弛有度，若合符節"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00272', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「出版的書被買走，然後又被脫手，直到來到下一個主人手中，書本才算重生。書就是這樣幾經復活， 在人與人之間建立連結。」 根據上文，下列選項對於書本的解讀，何者最適當？', '["書本放在書店的書架上就只是商品，沒有絲毫意義", "書本有自己的思想，遇見契合的主人就彷彿有了生命", "書本接連被讀者買回家，成為前後任主人間溝通的媒介", "書本的生命週期短暫，需要不斷經過生而死、死而生的循環"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00273', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「當企業領袖看到市場開始變化，於是設法推動組織轉型，此時會面臨矛盾的情況。一方面，需要令 人信服的數據，以提出理由說明轉型的必要，證明公司即將面臨『危急關頭』；另一方面，等到有關 破壞性趨勢和市場變化的公開數據，已足以令人信服時，機會之窗已經縮小了，甚至已經消失。當公 司真正面對危急關頭時，企業領袖會面對嚴酷的現實：在彈性極為重要的時刻，危急關頭的情況卻導 致公司更僵化，妨礙進行變革。」 根據上文，下列敘述何者正確？', '["企業領袖必須等市場數據完全公開，再進行趨勢分析，才符合科學精神", "等市場危機的正式數據被公開時，變革的契機早已逐漸消失，無力回天", "當危急關頭來臨時，組織因受到巨大的壓力，變革成功的機會才會大大提升", "變革是企業領袖最致命弱點，按部就班、穩紮穩打才是企業成長的不二原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
